const req = $input.first().json;
return [{ json: {
  token: (req.headers.authorization || '').replace(/^Bearer\s+/i, '') || req.query?.token,
  timestamp: req.headers['x-caiac-timestamp'],
  signature: req.headers['x-caiac-signature']
}}];

const auth = $input.first().json;
const client_id = auth.client_id;
if (!client_id) throw new Error('Unauthorized');
return [{ json: { client_id } }];

const rows = $input.all();

const items = rows
  .filter(r => r.json.id)
  .map(r => {
    const d = r.json;
    if (d.type === 'ai_conversation') {
      const count = parseInt(d.count_val, 10) || 0;
      return {
        id: d.id,
        type: 'ai_conversation',
        title: 'AI Research Session',
        subtitle: count === 1 ? '1 message' : `${count} messages`,
        timestamp: d.timestamp,
      };
    }
    return {
      id: d.id,
      type: 'workflow_run',
      title: 'New Inquiry Received',
      subtitle: 'Lead submitted and routed',
      timestamp: d.timestamp,
    };
  });

return [{ json: { items } }];
